mapper.select:
/* SQL ID : SeminarAtndDAO.selectStd 설 명 : 세미나 참석 수강생 정보 조회 */ SELECT A.STD_ID AS stdNo , A.USER_ID AS userId , (SELECT DEPTNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS deptNm , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS userNm , B.SMNR_ATND_ID AS seminarAtndId , B.ATND_SCNDS AS atndTime , B.ATND_SDTTM AS atndDttm , B.ATND_STSCD AS atndCd , B.ATND_MEMO AS atndMemo , (SELECT S.SMNR_MNTS FROM TB_LMS_SMNR S WHERE S.SMNR_ID = #{seminarId}) AS seminarTime
, ( SELECT CASE WHEN (TO_DATE(S.SMNR_SDTTM, 'YYYYMMDDHH24MISS') - SYSDATE) * 86400 > 0 THEN '대기' WHEN (TO_DATE(S.SMNR_SDTTM, 'YYYYMMDDHH24MISS') - SYSDATE) * 86400 < 0 AND (TO_DATE(S.SMNR_EDTTM, 'YYYYMMDDHH24MISS') - SYSDATE) * 86400 > 0 THEN '진행' WHEN (TO_DATE(S.SMNR_EDTTM, 'YYYYMMDDHH24MISS') - SYSDATE) * 86400 < 0 THEN '완료' END FROM TB_LMS_SMNR S WHERE S.SMNR_ID = #{seminarId} ) AS seminarStatus
FROM TB_LMS_ATNDLC_SBJCT A LEFT JOIN TB_LMS_SMNR_ATND B ON A.STD_ID = B.STD_ID AND B.SMNR_ID = #{seminarId} WHERE A.STD_ID = #{stdNo}

mapper.update:
		/*
             SQL ID : SeminarAtndDAO.update
            	 설  명 : 세미나 참석 수정
         */
		INSERT INTO TB_LMS_SMNR_ATND (
              SMNR_ATND_ID
			, SMNR_ID
			, STD_ID
			, USER_ID
			, ATND_SDTTM
			, ATND_SCNDS
			, ATND_STSCD
			, CNTN_DVC_TYCD
			, RGTR_IP
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
		) VALUES (
			  #{seminarAtndId}
         	, #{seminarId}
         	, #{stdNo}
         	, #{userId}
         	, IFNULL(#{atndDttm}, FN_DTTM())
         	, IFNULL(#{atndTime}, 0)
         	, IFNULL(#{atndCd}, 'START')
         	, IFNULL(#{deviceTypeCd}, '-')
         	, IFNULL(#{regIp}, '-')
         	, #{rgtrId}
         	, FN_DTTM()
         	, #{mdfrId}
         	, FN_DTTM()
        )
        ON DUPLICATE KEY
        UPDATE
        	  MDFR_ID = #{mdfrId}
         	, MOD_DTTM = FN_DTTM()

         	, ATND_SCNDS = #{atndTime}


         	, ATND_STSCD = #{atndCd}

		/*
             SQL ID : SeminarAtndDAO.updateMemo
            	 설  명 : 수강생 메모 수정
         */
         INSERT INTO TB_LMS_SMNR_ATND (
              SMNR_ATND_ID
			, SMNR_ID
			, STD_ID
			, USER_ID
			, CNTN_DVC_TYCD
			, ATND_MEMO
			, RGTR_IP
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
		) VALUES (
			  #{seminarAtndId}
         	, #{seminarId}
         	, #{stdNo}
         	, #{userId}
         	, IFNULL(#{deviceTypeCd}, '-')
         	, #{atndMemo}
         	, IFNULL(#{regIp}, '-')
         	, #{rgtrId}
         	, FN_DTTM()
         	, #{mdfrId}
         	, FN_DTTM()
        )
        ON DUPLICATE KEY
        UPDATE
        	  MDFR_ID = #{mdfrId}
         	, MOD_DTTM = FN_DTTM()
         	, ATND_MEMO = #{atndMemo}
